// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
	// STRY0100152 
	if(isLoading){
		peformDurationCheck(newValue);
		return;
	}

	peformDurationCheck();
	function peformDurationCheck(newValue){
		var duration = getDateFromFormat(newValue, g_user_date_time_format);

		// STRY0091294
		var isSuspenseDateRequired = g_scratchpad.isSuspenseDateRequired;
		g_form.setMandatory('duration',isSuspenseDateRequired == 'true'); // To make mandatory

		// need to set the message even on load
		if (g_scratchpad.totalChildDuration >  duration){
			g_form.showFieldMsg('duration', getMessage('Tasker - Warning: Parent duration shorter than the durations of subtasks'),'error', false);
			g_form.showFieldMsg('duration', getMessage('Tasker - Duration Warning - Sum of the duration of all subtasks is') + g_scratchpad.totalChildDurationDisplay,'error', false);
		}

		g_form.showFieldMsg('duration', getMessage('Tasker - Template Estimated Duration Help Text'), 'info', false); 		
	}
}
